from flask import Flask
from pymongo import MongoClient

app = Flask(__name__)
client = MongoClient('localhost', 27017)
db = client['content_management_system']

@app.route('/user_profile/<username>', methods=['GET'])
def get_user_profile(username):
    user_profile = db.user_profiles.find_one({'username': username})
    return user_profile

@app.route('/documents', methods=['GET'])
def get_documents():
    documents = list(db.documents.find())
    return {'documents': documents}

@app.route('/aggregation', methods=['GET'])
def aggregation_pipeline():
    pipeline = [
        {'$group': {'_id': '$category', 'count': {'$sum': 1}}}
    ]
    result = list(db.documents.aggregate(pipeline))
    return {'result': result}

if __name__ == '__main__':
    app.run(debug=True)